sys_script_include.script:
var ItsmaUtils = Class.create();
ItsmaUtils.prototype = {
    initialize: function() {},

    // Generalized field lookup with error handling
    getFieldValue: function(requestTypeSysId, fieldName, defaultValue) {
        try {
            if (!requestTypeSysId) {
                gs.error("ItsmaUtils.getFieldValue: requestTypeSysId is null or undefined");
                return defaultValue;
            }
            if (!fieldName) {
                gs.error("ItsmaUtils.getFieldValue: fieldName is null or undefined");
                return defaultValue;
            }

            var gr = new GlideRecord('x_1903513_mini_i_0_request_type');
            if (gr.get(requestTypeSysId)) {
                var value = gr.getValue(fieldName);
                if (!value) {
                    gs.warn("ItsmaUtils.getFieldValue: Field '" + fieldName + "' is empty for sys_id " + requestTypeSysId);
                    return defaultValue;
                }
                return value;
            } else {
                gs.error("ItsmaUtils.getFieldValue: No record found for sys_id " + requestTypeSysId);
            }
        } catch (e) {
            gs.error("ItsmaUtils.getFieldValue: Exception occurred - " + e.message);
        }
        return defaultValue;
    },

    // Specialized helper using getFieldValue
    getAssignmentGroup: function(requestTypeSysId) {
        return this.getFieldValue(requestTypeSysId, 'u_fulfillment_group', null);
    },

    // Specialized helper using getFieldValue
    getDefaultPriority: function(requestTypeSysId) {
        return this.getFieldValue(requestTypeSysId, 'u_default_priority', 3);
    },

    type: 'ItsmaUtils'
};
